class Node:
 def __init__(self, val=False, is_leaf=False, top_left=None, top_right=None, bottom_left=None, bottom_right=None):
  self.val=val
  self.isLeaf=is_leaf
  self.topLeft=top_left
  self.topRight=top_right
  self.bottomLeft=bottom_left
  self.bottomRight=bottom_right

class Solution1:
    def construct(self,grid):
        return self.recurse(grid,0,0,len(grid))

    def recurse(self,grid,row,col,limit):
        if self.allTheSameValue(grid,row,col,limit):
            return Node(grid[row][col]==1,True)
        else:
            root=Node(False,False)
            root.topLeft=self.recurse(grid,row,col,limit//2)
            root.topRight=self.recurse(grid,row,col+limit//2,limit//2)
            root.bottomLeft=self.recurse(grid,row+limit//2,col,limit//2)
            root.bottomRight=self.recurse(grid,row+limit//2,col+limit//2,limit//2)
            return root

    def allTheSameValue(self,grid,row,col,limit):
        val=grid[row][col]
        for i in range(row,row+limit):
            for j in range(col,col+limit):
                if val!=grid[i][j]:
                   return False
        return True

